def RelativelyVeryAmple {X S : Scheme.{u}} (f : X ⟶ S) (_L : X.Modules) : Prop :=
  ∃ (V : S.Modules) (i : X ⟶ relativeProj S V),
    IsClosedImmersion i ∧ i ≫ relativeProj.structureMorphism S V = f

